local CS = CS
local YXUtility = CS.YXUtility

---@class LFileHelper
local LFileHelper = LxClass("LFileHelper", nil)

---WebGL上不适用该接口
function LFileHelper.WriteAllText(path, content)
    CS.FileWriteText(path, content)
end

---WebGL上不适用该接口
function LFileHelper.WriteAllBytes(path, content)
    CS.FileWriteBytes(path, content)
end

---WebGL上不适用该接口
function LFileHelper.ReadAllText(path, content, isWithBom)
    return CS.FileReadText(path, content, isWithBom)
end

---WebGL上不适用该接口
function LFileHelper.ReadAllBytes(path)
    return CS.FileReadBytes(path)
end


function LFileHelper._WriteAllTextForLocalStorage(path, content)
    return LNativeHelper.LocalStorageWrite(path, content)
end

function LFileHelper._WriteAllTextForLocalStorage(path, content)
    return LNativeHelper.LocalStorageWrite(path, content)
end

function LFileHelper._WriteAllBytesForLocalStorage(path, content)
    content = YXUtility.Base64EncodeBytes(content)
    return LNativeHelper.LocalStorageWrite(path, content)
end

function LFileHelper._ReadAllTextForLocalStorage(path)
    return LNativeHelper.LocalStorageRead(path)
end

function LFileHelper._ReadAllBytesForLocalStorage(path)
    local content = LNativeHelper.LocalStorageRead(path)
    if not string.isempty(content) then
        content = YXUtility.Base64DecodeToBytes(content)
    end
    return content
end

function LFileHelper._DeleteForLocalStorage(path)
    LNativeHelper.LocalStorageDelete(path)
end


---同步读取 适配WebGL
function LFileHelper.WriteAllTextToCache(path, content)
    if CS.IsWebGL() then
        if LWxHelper.IsMiniGamePlatform() then
            return LWxHelper.WxWriteFileText(path, content)
        else
            return LFileHelper._WriteAllTextForLocalStorage(path, content)
        end
    else
        CS.FileWriteText(path, content)
    end
    return true
end

---同步写 适配WebGL
function LFileHelper.WriteAllBytesToCache(path, content)
    if CS.IsWebGL() then
        if LWxHelper.IsMiniGamePlatform() then
            return LWxHelper.WxWriteFileBytes(path, content)
        else
            return LFileHelper._WriteAllBytesForLocalStorage(path, content)
        end
    else
        CS.FileWriteBytes(path, content)
    end
    return true
end

---同步读取 适配WebGL
function LFileHelper.ReadAllTextFromCache(path)
    if CS.IsWebGL() then
        if LWxHelper.IsMiniGamePlatform() then
            if LWxHelper.WxFileExists(path) then
                return LWxHelper.WxReadFileText(path)
            end
        else
            return LFileHelper._ReadAllTextForLocalStorage(path)
        end
    else
        if CS.FileExists(path) then
            return CS.FileReadText(path)
        end
    end
    return nil
end

---同步写 适配WebGLN
function LFileHelper.ReadAllBytesFromCache(path)
    if CS.IsWebGL() then
        if LWxHelper.IsMiniGamePlatform() then
            if LWxHelper.WxFileExists(path) then
                return LWxHelper.WxReadFileBytes(path)
            end
        else
            return LFileHelper._ReadAllBytesForLocalStorage(path)
        end
    else
        if CS.FileExists(path) then
            return CS.FileReadBytes(path)
        end
    end
    return nil
end

---同步写 适配WebGL
function LFileHelper.CacheDelete(path)
    if CS.IsWebGL() then
        if LWxHelper.IsMiniGamePlatform() then
            if LWxHelper.WxFileExists(path) then
                LWxHelper.WxDeleteFile(path)
            end
        else
            return LFileHelper._DeleteForLocalStorage(path)
        end
    else
        if CS.FileExists(path) then
            return CS.FileDelete(path)
        end
    end
    return nil
end

return LFileHelper
